export const getStandings = async (event: Electron.IpcMainEvent) => {
  try {
    const response = await fetch(
      `${CONSTANTS.LMU_API_BASE_URL}/rest/watch/standings`,
    );
    if (!response.ok) {
      event.reply(CONSTANTS.API.GET_STANDINGS, {
        status: 'error',
        message: `API responded with status ${response.status}`,
      });
      return;
    }

    const data = await response.json();
    event.reply(CONSTANTS.API.GET_STANDINGS, { status: 'success', data });
   } catch (error: unknown) {
    event.reply(CONSTANTS.API.GET_STANDINGS, {
      status: 'error',
         message: toErrorMessage(error),
    });
  }
};

